import java.util.Arrays;

public class HashFunctions {

    public int sumHash(String s, int m) {
        // TODO: return (sum of char values) % m
        int sum = 0;
        return sum % m;
    }

    public int polynomialHash(String s, int m) {
        // polynomial rolling hash: h = (h*31 + char) % m for each char
        long h = 0;
        // TODO: for each char c in s: h = (h * 31 + c) % m
        return (int) h;
    }

    public void analyzeDistribution(String[] words, int m) {
        int[] sumBuckets  = new int[m];
        int[] polyBuckets = new int[m];
        for (String w : words) {
            sumBuckets[sumHash(w, m)]++;
            polyBuckets[polynomialHash(w, m)]++;
        }
        long sumCollisions  = Arrays.stream(sumBuckets).filter(x -> x > 1).map(x -> x-1).sum();
        long polyCollisions = Arrays.stream(polyBuckets).filter(x -> x > 1).map(x -> x-1).sum();
        System.out.println("Sum hash collisions:  " + sumCollisions);
        System.out.println("Poly hash collisions: " + polyCollisions);
        System.out.println("Poly is better: " + (polyCollisions < sumCollisions));
    }

    public static void main(String[] args) {
        HashFunctions hf = new HashFunctions();
        String[] words = {"cat","act","tac","dog","god","god","log","fog","bog"};
        System.out.println("sumHash('cat',10): "  + hf.sumHash("cat", 10));
        System.out.println("polyHash('cat',10): " + hf.polynomialHash("cat", 10));
        System.out.println();
        hf.analyzeDistribution(words, 10);
    }
}

